  ('fire-eq-tech-moex-02589', 'fire-eq-tech', 'fire-eq-tech-moex-100-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依各類場所消防安全設備檢修及申報作業基準，定溫式局限型探測器當其標稱動作溫度與周圍溫度之差 超過幾度時，其動作時間得加倍計算？', '["20", "30", "40", "50"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "c70ccee8d47f", "answer_pdf_sha1": "12850e9e4ccc", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
